const { randomUUID } = require('node:crypto');

module.exports = {
  updateTaskStatus: (taskId, status) => {
    if (!taskId || !['todo', 'done'].includes(status)) {
      return null;
    }
    return {
      id: taskId,
      status,
    };
  },
};
